package com.southsouthwest.framelog.ui.util

import com.southsouthwest.framelog.data.db.entity.ApertureIncrements
import com.southsouthwest.framelog.data.db.entity.ShutterIncrements

/**
 * Generates valid aperture and shutter speed value lists for stepper controls.
 *
 * All values use the canonical storage format (same strings stored in the database):
 *   Apertures: "f/1.4", "f/8", "f/11" etc.
 *   Shutter speeds: "B", "30s", "1s", "1/125", "1/1000" etc.
 *
 * Lists are ordered slow→fast (shutter) or wide→narrow (aperture) so that stepping
 * "up" always increases exposure.
 */
object ExposureValues {

    // ---------------------------------------------------------------------------
    // Shutter speed sequences
    // ---------------------------------------------------------------------------

    // Full stops: B + 19 stops from 30s to 1/8000
    private val SHUTTER_FULL = listOf(
        "B",
        "30s", "15s", "8s", "4s", "2s", "1s",
        "1/2", "1/4", "1/8", "1/15", "1/30", "1/60",
        "1/125", "1/250", "1/500", "1/1000", "1/2000", "1/4000", "1/8000",
    )

    // Half stops: same range with intermediate values added
    private val SHUTTER_HALF = listOf(
        "B",
        "30s", "20s", "15s", "10s", "8s", "6s", "4s", "3s", "2s", "1.5s", "1s",
        "1/1.5", "1/2", "1/3", "1/4", "1/6", "1/8", "1/10", "1/15", "1/20",
        "1/30", "1/45", "1/60", "1/90", "1/125", "1/180", "1/250", "1/350",
        "1/500", "1/750", "1/1000", "1/1500", "1/2000", "1/3000", "1/4000",
        "1/6000", "1/8000",
    )

    // Third stops: standard photographic values at 1/3 stop spacing
    private val SHUTTER_THIRD = listOf(
        "B",
        "30s", "25s", "20s", "15s", "13s", "10s", "8s", "6s", "5s", "4s", "3s",
        "2.5s", "2s", "1.6s", "1.3s", "1s",
        "1/1.3", "1/1.6", "1/2", "1/2.5", "1/3", "1/4", "1/5", "1/6",
        "1/8", "1/10", "1/13", "1/15", "1/20", "1/25", "1/30", "1/40", "1/50",
        "1/60", "1/80", "1/100", "1/125", "1/160", "1/200", "1/250", "1/320", "1/400",
        "1/500", "1/640", "1/800", "1/1000", "1/1250", "1/1600", "1/2000", "1/2500",
        "1/3200", "1/4000", "1/5000", "1/6400", "1/8000",
    )

    /**
     * Returns the complete shutter speed list for the given increment type,
     * ordered slowest → fastest (B first, 1/8000 last).
     */
    fun shutterSpeeds(increments: ShutterIncrements): List<String> = when (increments) {
        ShutterIncrements.FULL -> SHUTTER_FULL
        ShutterIncrements.HALF -> SHUTTER_HALF
        ShutterIncrements.THIRD -> SHUTTER_THIRD
    }

    /**
     * Returns the human-readable display string for a stored shutter speed value.
     *
     * Convention from the DESIGN decisions doc:
     *   "1/125" → "125"  (drop the "1/" — implied by context)
     *   "2s"    → "2s"   (keep the s-suffix for whole seconds)
     *   "B"     → "B"
     */
    fun shutterDisplayValue(stored: String): String = when {
        stored == "B" -> "B"
        stored.endsWith("s") -> stored
        stored.startsWith("1/") -> stored.removePrefix("1/")
        else -> stored // e.g. "1/1.5" keeps as-is if doesn't match above
    }

    /**
     * Returns true if this shutter speed value should render in the accent color.
     * Whole-second values and bulb are "long exposure" by convention (red numbers on
     * classic cameras like the Canon AE-1).
     */
    fun isLongExposure(stored: String): Boolean =
        stored == "B" || stored.endsWith("s")

    // ---------------------------------------------------------------------------
    // Aperture sequences
    // ---------------------------------------------------------------------------

    // Full stops: f/1 through f/64
    private val APERTURE_FULL = listOf(
        1.0f, 1.4f, 2.0f, 2.8f, 4.0f, 5.6f, 8.0f, 11.0f, 16.0f, 22.0f, 32.0f, 45.0f, 64.0f,
    )

    // Half stops: intermediate values added between full stops
    private val APERTURE_HALF = listOf(
        1.0f, 1.2f, 1.4f, 1.7f, 2.0f, 2.4f, 2.8f, 3.3f, 4.0f, 4.8f, 5.6f, 6.7f,
        8.0f, 9.5f, 11.0f, 13.0f, 16.0f, 19.0f, 22.0f, 27.0f, 32.0f,
    )

    // Third stops: standard photographic values at 1/3 stop spacing
    private val APERTURE_THIRD = listOf(
        1.0f, 1.1f, 1.2f, 1.4f, 1.6f, 1.8f, 2.0f, 2.2f, 2.5f, 2.8f, 3.2f, 3.5f,
        4.0f, 4.5f, 5.0f, 5.6f, 6.3f, 7.1f, 8.0f, 9.0f, 10.0f, 11.0f, 13.0f, 14.0f,
        16.0f, 18.0f, 20.0f, 22.0f, 25.0f, 29.0f, 32.0f,
    )

    /**
     * Returns valid aperture strings for a lens, bounded by [maxAperture] (widest) and
     * [minAperture] (narrowest), using the lens's [increments] type.
     *
     * Ordered widest → narrowest (f/1.4 first, f/22 last) — "up" step = wider = more exposure.
     *
     * A small epsilon (0.05) is used in the bounds check to handle floating-point edge cases
     * where lens.maxAperture = 1.4f might not exactly match the list value 1.4f.
     */
    fun apertures(
        maxAperture: Float,
        minAperture: Float,
        increments: ApertureIncrements,
    ): List<String> {
        val all = when (increments) {
            ApertureIncrements.FULL -> APERTURE_FULL
            ApertureIncrements.HALF -> APERTURE_HALF
            ApertureIncrements.THIRD -> APERTURE_THIRD
        }
        return all
            .filter { it >= maxAperture - 0.05f && it <= minAperture + 0.05f }
            .map { formatAperture(it) }
    }

    /**
     * Formats a Float aperture value to the canonical "f/X" storage string.
     * Integer values omit the decimal point: 8.0f → "f/8", 1.4f → "f/1.4".
     */
    fun formatAperture(value: Float): String =
        if (value == value.toLong().toFloat()) "f/${value.toLong()}" else "f/$value"

    /**
     * Parses a canonical "f/X" string back to a Float for bounds comparison.
     * Returns null if the string is malformed.
     */
    fun parseAperture(stored: String): Float? =
        stored.removePrefix("f/").toFloatOrNull()

    // ---------------------------------------------------------------------------
    // Exposure compensation
    // ---------------------------------------------------------------------------

    /**
     * Valid exposure compensation values in 1/3 stop increments from -3.0 to +3.0 EV.
     * Null is not in this list — the ViewModel handles null separately as "no EC applied".
     */
    val exposureCompensationValues: List<Float> = buildList {
        // Generate -3.0, -2.67, -2.33 … 0 … 2.33, 2.67, 3.0
        // Use integer arithmetic to avoid float accumulation error.
        for (thirds in -9..9) {
            add(thirds / 3.0f)
        }
    }

    /**
     * Formats an EC float for display, e.g. 0.0 → "0", 0.333 → "+⅓", -1.0 → "-1".
     * Uses vulgar fractions for third-stop values for a clean camera-dial aesthetic.
     */
    fun formatExposureCompensation(value: Float): String {
        val thirds = (value * 3).toInt()
        val wholePart = thirds / 3
        val remainder = thirds % 3
        val sign = if (value > 0f) "+" else if (value < 0f) "-" else ""
        val absWhole = Math.abs(wholePart)
        val absFrac = Math.abs(remainder)
        return when {
            thirds == 0 -> "0"
            absFrac == 0 -> "$sign$absWhole"
            absWhole == 0 -> "$sign${fraction(absFrac)}"
            else -> "$sign$absWhole${fraction(absFrac)}"
        }
    }

    private fun fraction(thirds: Int): String = when (thirds) {
        1 -> "⅓"
        2 -> "⅔"
        else -> ""
    }
}

package com.southsouthwest.framelog.data.db

import android.content.Context
import androidx.room.Database
import androidx.room.Room
import androidx.room.RoomDatabase
import androidx.room.Transaction
import androidx.room.TypeConverters
import com.southsouthwest.framelog.data.db.dao.CameraBodyDao
import com.southsouthwest.framelog.data.db.dao.FilmStockDao
import com.southsouthwest.framelog.data.db.dao.FilterDao
import com.southsouthwest.framelog.data.db.dao.FrameDao
import com.southsouthwest.framelog.data.db.dao.KitDao
import com.southsouthwest.framelog.data.db.dao.KitFilterDao
import com.southsouthwest.framelog.data.db.dao.KitLensDao
import com.southsouthwest.framelog.data.db.dao.LensDao
import com.southsouthwest.framelog.data.db.dao.RollDao
import com.southsouthwest.framelog.data.db.dao.RollFilterDao
import com.southsouthwest.framelog.data.db.dao.RollLensDao
import com.southsouthwest.framelog.data.db.entity.CameraBody
import com.southsouthwest.framelog.data.db.entity.FilmStock
import com.southsouthwest.framelog.data.db.entity.Filter
import com.southsouthwest.framelog.data.db.entity.Frame
import com.southsouthwest.framelog.data.db.entity.FrameFilter
import com.southsouthwest.framelog.data.db.entity.Kit
import com.southsouthwest.framelog.data.db.entity.KitFilter
import com.southsouthwest.framelog.data.db.entity.KitLens
import com.southsouthwest.framelog.data.db.entity.Lens
import com.southsouthwest.framelog.data.db.entity.Roll
import com.southsouthwest.framelog.data.db.entity.RollFilter
import com.southsouthwest.framelog.data.db.entity.RollLens

/**
 * The single Room database for FRAME//LOG. All photography data lives here.
 * App configuration (active roll ID, onboarding flag, settings) lives in SharedPreferences.
 *
 * Version history:
 *   1 — initial schema
 *
 * Multi-DAO transactions are implemented here as @Transaction methods so they have access
 * to all DAOs. The Repository layer calls these methods rather than coordinating DAOs itself.
 */
@Database(
    entities = [
        CameraBody::class,
        Lens::class,
        Filter::class,
        FilmStock::class,
        Roll::class,
        RollLens::class,
        RollFilter::class,
        Frame::class,
        FrameFilter::class,
        Kit::class,
        KitLens::class,
        KitFilter::class,
    ],
    version = 1,
    exportSchema = true,
)
@TypeConverters(Converters::class)
abstract class AppDatabase : RoomDatabase() {

    abstract fun rollDao(): RollDao
    abstract fun frameDao(): FrameDao
    abstract fun cameraBodyDao(): CameraBodyDao
    abstract fun lensDao(): LensDao
    abstract fun filterDao(): FilterDao
    abstract fun filmStockDao(): FilmStockDao
    abstract fun kitDao(): KitDao
    abstract fun rollLensDao(): RollLensDao
    abstract fun rollFilterDao(): RollFilterDao
    abstract fun kitLensDao(): KitLensDao
    abstract fun kitFilterDao(): KitFilterDao

    // ---------------------------------------------------------------------------
    // Multi-DAO transactions
    // These are the three atomic operations described in the architecture docs.
    // ---------------------------------------------------------------------------

    /**
     * Atomically creates a roll with all its associated lenses, filters, and pre-generated
     * frame slots. Returns the auto-generated roll ID.
     *
     * The [roll] must have id = 0 (auto-generate). The rollId fields in [rollLenses],
     * [rollFilters], and [frames] are ignored — the actual generated rollId is substituted.
     *
     * All four writes succeed or none do.
     */
    @Transaction
    open suspend fun createRollWithAssociations(
        roll: Roll,
        rollLenses: List<RollLens>,
        rollFilters: List<RollFilter>,
        frames: List<Frame>,
    ): Long {
        val rollId = rollDao().insertRoll(roll)
        rollLenses.forEach { rollLensDao().insertRollLens(it.copy(rollId = rollId.toInt())) }
        rollFilters.forEach { rollFilterDao().insertRollFilter(it.copy(rollId = rollId.toInt())) }
        frameDao().insertFrames(frames.map { it.copy(rollId = rollId.toInt()) })
        return rollId
    }

    /**
     * Atomically saves a kit (create or update) with a wholesale replacement of its
     * lens and filter associations. Returns the kit ID.
     *
     * For a new kit, [kit].id must be 0. For an update, [kit].id must be the existing kit ID.
     * Wholesale replace is used (delete all, reinsert current set) rather than delta updates —
     * kits are edited deliberately at home, not in the field, so simplicity is preferred.
     *
     * All writes succeed or none do.
     */
    @Transaction
    open suspend fun saveKitWithAssociations(
        kit: Kit,
        kitLenses: List<KitLens>,
        kitFilters: List<KitFilter>,
    ): Long {
        val kitId: Long = if (kit.id == 0) {
            kitDao().insertKit(kit)
        } else {
            kitDao().updateKit(kit)
            kit.id.toLong()
        }

        // Wholesale replace: clear existing associations, then reinsert the current set.
        kitLensDao().deleteAllKitLenses(kitId.toInt())
        kitLenses.forEach { kitLensDao().insertKitLens(it.copy(kitId = kitId.toInt())) }

        kitFilterDao().deleteAllKitFilters(kitId.toInt())
        kitFilters.forEach { kitFilterDao().insertKitFilter(it.copy(kitId = kitId.toInt())) }

        return kitId
    }

    // ---------------------------------------------------------------------------
    // Singleton
    // ---------------------------------------------------------------------------

    companion object {
        @Volatile
        private var instance: AppDatabase? = null

        /**
         * Returns the singleton AppDatabase instance, creating it if necessary.
         * Uses double-checked locking to ensure thread safety without synchronizing
         * every call after initialization.
         */
        fun getInstance(context: Context): AppDatabase {
            return instance ?: synchronized(this) {
                instance ?: Room.databaseBuilder(
                    context.applicationContext,
                    AppDatabase::class.java,
                    "framelog.db",
                ).build().also { instance = it }
            }
        }

        /**
         * Closes and clears the singleton instance.
         * Must be called before overwriting the database file during a backup restore.
         * After calling this, the next call to [getInstance] will open a fresh connection.
         */
        fun closeInstance() {
            synchronized(this) {
                instance?.close()
                instance = null
            }
        }
    }
}

package com.southsouthwest.framelog.data.db.relation

import androidx.room.Embedded
import androidx.room.Relation
import com.southsouthwest.framelog.data.db.entity.Frame
import com.southsouthwest.framelog.data.db.entity.Roll
import com.southsouthwest.framelog.data.db.entity.RollFilter
import com.southsouthwest.framelog.data.db.entity.RollLens

/**
 * A Roll with all its associated lenses, filters, and pre-generated frame slots.
 *
 * Used by the Quick Screen and Roll Journal — one database trip returns everything needed.
 * Queries returning this type must be annotated with @Transaction.
 */
data class RollWithDetails(
    @Embedded val roll: Roll,

    /** Lenses available during this roll, each with full Lens details. */
    @Relation(
        entity = RollLens::class,
        parentColumn = "id",
        entityColumn = "rollId",
    )
    val lenses: List<RollLensWithLens>,

    /** Filters available during this roll, each with full Filter details. */
    @Relation(
        entity = RollFilter::class,
        parentColumn = "id",
        entityColumn = "rollId",
    )
    val filters: List<RollFilterWithFilter>,

    /** All pre-generated frame slots, ordered by frameNumber. */
    @Relation(
        parentColumn = "id",
        entityColumn = "rollId",
    )
    val frames: List<Frame>,
)

package com.southsouthwest.framelog.data.db.dao

import androidx.room.Dao
import androidx.room.Delete
import androidx.room.Insert
import androidx.room.Query
import androidx.room.Update
import com.southsouthwest.framelog.data.db.entity.FilmStock
import kotlinx.coroutines.flow.Flow

@Dao
interface FilmStockDao {

    /**
     * Search film stocks by name or make, optionally including discontinued stocks.
     * Discontinued stocks are hidden by default to keep pickers clean, but still exist
     * in the database to preserve historical roll data.
     */
    @Query("SELECT * FROM film_stocks WHERE (name LIKE '%' || :query || '%' OR make LIKE '%' || :query || '%') AND (discontinued = 0 OR :includeDiscontinued = 1) ORDER BY make ASC, name ASC")
    fun searchFilmStocks(query: String, includeDiscontinued: Boolean = false): Flow<List<FilmStock>>

    @Query("SELECT * FROM film_stocks WHERE id = :id")
    fun getFilmStockById(id: Int): Flow<FilmStock>

    @Insert
    suspend fun insertFilmStock(filmStock: FilmStock)

    @Update
    suspend fun updateFilmStock(filmStock: FilmStock)

    @Delete
    suspend fun deleteFilmStock(filmStock: FilmStock)
}

