                    StepperButton(label = "−", action = actionRunCallback<ShutterDownAction>())
                    Spacer(modifier = GlanceModifier.width(4.dp))
                    StepperValue(text = shutterDisplay, isLongExposure = isLongExposure)
                    Spacer(modifier = GlanceModifier.width(4.dp))
                    // + = slower = lower index (more exposure)
                    StepperButton(label = "+", action = actionRunCallback<ShutterUpAction>())
                }
            }
        }

        // --- Divider ---
        HorizontalDivider()

        // --- Rows 3–4: Log Frame button ---
        // Note: widget cannot show confirmation dialogs. Tapping Log Frame always writes
        // immediately, even if the frame was previously logged (silent overwrite).
        Box(
            modifier = GlanceModifier
                .fillMaxWidth()
                .defaultWeight()
                .clickable(actionRunCallback<LogFrameAction>()),
            contentAlignment = Alignment.Center,
        ) {
            Text(
                text = "log frame",
                style = TextStyle(
                    fontSize = 15.sp,
                    fontWeight = FontWeight.Medium,
                    color = GlanceTheme.colors.onSurface,
                    textAlign = TextAlign.Center,
                ),
