@Composable
private fun StepperButton(label: String, action: Action) {
    Box(
        modifier = GlanceModifier
            .size(28.dp)
            .background(GlanceTheme.colors.surfaceVariant)
            .cornerRadius(6.dp)
            .clickable(action),
        contentAlignment = Alignment.Center,
    ) {
        Text(
            text = label,
            style = TextStyle(
                fontSize = 16.sp,
                fontWeight = FontWeight.Medium,
                color = GlanceTheme.colors.onSurfaceVariant,
                textAlign = TextAlign.Center,
            ),
        )
    }
}

/**
 * Read-only value display between the stepper buttons.
 *
 * Long-exposure shutter values (whole seconds and B) render in the error color,
 * matching the camera dial convention (red long-exposure numbers on film cameras like
 * the Canon AE-1) and consistent with the Quick Screen stepper behavior.
 */
@Composable
private fun StepperValue(text: String, isLongExposure: Boolean) {
    val color = if (isLongExposure) GlanceTheme.colors.error else GlanceTheme.colors.onSurface
    Box(
        modifier = GlanceModifier
            .width(48.dp)
            .height(28.dp)
            .background(GlanceTheme.colors.surface),
        contentAlignment = Alignment.Center,
    ) {
        Text(
            text = text,
            style = TextStyle(
                fontSize = 15.sp,
                fontWeight = FontWeight.Medium,
                color = color,
                textAlign = TextAlign.Center,
            ),
        )
    }
}

/** Thin horizontal rule between widget layout sections. */
@Composable
private fun HorizontalDivider() {
    Box(
        modifier = GlanceModifier
            .fillMaxWidth()
            .height(1.dp)
            .background(GlanceTheme.colors.surfaceVariant),
    )
}

