            Spacer(modifier = GlanceModifier.height(4.dp))
            Text(
                text = "No roll loaded — tap to open",
                style = TextStyle(
                    fontSize = 10.sp,
                    color = GlanceTheme.colors.onSurfaceVariant,
                    textAlign = TextAlign.Center,
