package com.southsouthwest.framelog.ui.widget

import android.content.Context
import androidx.datastore.preferences.core.Preferences
import androidx.glance.GlanceId
import androidx.glance.appwidget.action.ActionCallback
import androidx.glance.appwidget.state.getAppWidgetState
import androidx.glance.appwidget.state.updateAppWidgetState
import androidx.glance.action.ActionParameters
import androidx.glance.state.PreferencesGlanceStateDefinition
import com.southsouthwest.framelog.data.AppPreferences
import com.southsouthwest.framelog.data.db.AppDatabase
import com.southsouthwest.framelog.data.db.entity.Frame
import com.southsouthwest.framelog.data.repository.FrameRepository
import kotlinx.coroutines.flow.first

// ---------------------------------------------------------------------------
// Stepper direction helpers
// ---------------------------------------------------------------------------

/**
 * Steps to the next value in [list] relative to [current], clamped at the boundaries.
 *
 * Both aperture and shutter lists are ordered "more exposure → less exposure":
 *   Aperture: widest first (f/1.4 … f/22)
 *   Shutter:  slowest first (B … 1/8000)
 *
 * "Up" (more exposure) = lower index  — wider aperture or slower shutter.
 * "Down" (less exposure) = higher index — narrower aperture or faster shutter.
 *
 * If [current] isn't in the list (e.g. stale state after roll change), snap to the midpoint.
 */
private fun stepUp(list: List<String>, current: String): String {
    if (list.isEmpty()) return current
    val idx = list.indexOf(current)
    val safeIdx = if (idx == -1) list.size / 2 else idx
    return list[(safeIdx - 1).coerceAtLeast(0)]
}

private fun stepDown(list: List<String>, current: String): String {
    if (list.isEmpty()) return current
    val idx = list.indexOf(current)
    val safeIdx = if (idx == -1) list.size / 2 else idx
    return list[(safeIdx + 1).coerceAtMost(list.size - 1)]
}

private fun parseList(raw: String): List<String> =
    raw.split(",").filter { it.isNotBlank() }

// ---------------------------------------------------------------------------
// Aperture stepper actions
// ---------------------------------------------------------------------------

/**
 * Increments aperture — moves to a wider aperture (lower f-number = lower index in list).
 * Reads current aperture and list from GlanceState, writes the new value, re-renders.
 */
class ApertureUpAction : ActionCallback {
    override suspend fun onAction(
        context: Context,
        glanceId: GlanceId,
        parameters: ActionParameters,
    ) {
        updateAppWidgetState(context, glanceId) { prefs ->
            val list = parseList(prefs[WidgetState.APERTURE_LIST] ?: "")
            val current = prefs[WidgetState.APERTURE] ?: ""
            prefs[WidgetState.APERTURE] = stepUp(list, current)
        }
        FrameLogWidget().update(context, glanceId)
    }
}

/**
 * Decrements aperture — moves to a narrower aperture (higher f-number = higher index in list).
 */
class ApertureDownAction : ActionCallback {
    override suspend fun onAction(
        context: Context,
        glanceId: GlanceId,
        parameters: ActionParameters,
    ) {
        updateAppWidgetState(context, glanceId) { prefs ->
            val list = parseList(prefs[WidgetState.APERTURE_LIST] ?: "")
            val current = prefs[WidgetState.APERTURE] ?: ""
            prefs[WidgetState.APERTURE] = stepDown(list, current)
        }
        FrameLogWidget().update(context, glanceId)
    }
}

// ---------------------------------------------------------------------------
// Shutter speed stepper actions
// ---------------------------------------------------------------------------

/**
 * Increments shutter — moves to a slower speed (more exposure = lower index in list).
 * Long-exposure values (B, whole seconds) render in the accent color automatically.
 */
class ShutterUpAction : ActionCallback {
    override suspend fun onAction(
        context: Context,
        glanceId: GlanceId,
        parameters: ActionParameters,
    ) {
        updateAppWidgetState(context, glanceId) { prefs ->
            val list = parseList(prefs[WidgetState.SHUTTER_LIST] ?: "")
            val current = prefs[WidgetState.SHUTTER] ?: ""
            prefs[WidgetState.SHUTTER] = stepUp(list, current)
        }
        FrameLogWidget().update(context, glanceId)
    }
}

/**
 * Decrements shutter — moves to a faster speed (less exposure = higher index in list).
 */
class ShutterDownAction : ActionCallback {
    override suspend fun onAction(
        context: Context,
        glanceId: GlanceId,
        parameters: ActionParameters,
    ) {
        updateAppWidgetState(context, glanceId) { prefs ->
            val list = parseList(prefs[WidgetState.SHUTTER_LIST] ?: "")
            val current = prefs[WidgetState.SHUTTER] ?: ""
            prefs[WidgetState.SHUTTER] = stepDown(list, current)
        }
        FrameLogWidget().update(context, glanceId)
    }
}

// ---------------------------------------------------------------------------
// Log Frame action
// ---------------------------------------------------------------------------

/**
 * Logs the current frame to Room using the aperture and shutter shown on the widget.
 *
 * Widget limitations vs Quick Screen:
 *   - No confirmation dialog for overwrite — silently overwrites a previously logged frame.
 *     (Widgets cannot show dialogs. The user can correct via the Frame Detail screen.)
 *   - No GPS capture — widgets cannot request location permission.
 *   - No filter changes — the widget does not manage active filter state. FrameFilter rows
 *     for the target frame are left unchanged (empty for a fresh slot).
 *   - No haptic feedback — widgets run outside the in-app process and cannot reliably
 *     trigger vibration via the accessibility-aware path used by the Quick Screen.
 *
 * After a successful write, the frame pointer advances to the next unlogged frame in
 * SharedPreferences, and FrameLogWidgetUpdater.update() fully refreshes the widget.
 */
class LogFrameAction : ActionCallback {
    override suspend fun onAction(
        context: Context,
        glanceId: GlanceId,
        parameters: ActionParameters,
    ) {
        // Read the current widget state from GlanceState (DataStore).
        // getAppWidgetState requires an explicit GlanceStateDefinition — no 2-arg convenience exists.
        val state: Preferences = getAppWidgetState(context, PreferencesGlanceStateDefinition, glanceId)
        val rollId = state[WidgetState.ROLL_ID] ?: return
        val frameNumber = state[WidgetState.FRAME_NUMBER] ?: return
        val aperture = state[WidgetState.APERTURE]
        val shutter = state[WidgetState.SHUTTER]

        val db = AppDatabase.getInstance(context)
        val appPrefs = AppPreferences(context)
        val frameRepository = FrameRepository(db)

        // Load the roll to find the target frame entity by frameNumber
        val rollWithDetails = db.rollDao().getRollById(rollId).first() ?: return
        val frame = rollWithDetails.frames.firstOrNull { it.frameNumber == frameNumber } ?: return

        // Build the updated frame.
        // GPS is null — the widget cannot request location permission.
        // lensId, exposureCompensation, and notes are retained from the existing frame slot
        // (set during the previous Quick Screen session or left at their defaults).
        val updatedFrame = Frame(
            id = frame.id,
            rollId = frame.rollId,
            frameNumber = frame.frameNumber,
            isLogged = true,
            loggedAt = System.currentTimeMillis(),
            aperture = aperture,
            shutterSpeed = shutter,
            lensId = frame.lensId,
            exposureCompensation = frame.exposureCompensation,
            lat = null,
            lng = null,
            notes = frame.notes,
        )

        // Atomic write: update frame, no filter changes (empty lists)
        frameRepository.logFrame(updatedFrame, emptyList(), emptyList())

        // Advance the frame pointer to the next unlogged frame after the one just logged.
        // We use the pre-write rollWithDetails.frames because frames before frameNumber that
        // were already unlogged remain unlogged — we only want frames AFTER the current one.
        val nextUnlogged = rollWithDetails.frames
            .filter { it.frameNumber > frameNumber && !it.isLogged }
            .minByOrNull { it.frameNumber }

        if (nextUnlogged != null) {
            appPrefs.setCurrentFrameNumber(rollId, nextUnlogged.frameNumber)
        }

        // Full widget refresh — re-reads from Room to pick up the updated frame state
        // and the new frame pointer position.
        FrameLogWidgetUpdater.update(context)
    }
}

package com.southsouthwest.framelog.ui.rolls

import android.app.Application
import androidx.lifecycle.AndroidViewModel
import androidx.lifecycle.viewModelScope
import com.southsouthwest.framelog.data.AppPreferences
import com.southsouthwest.framelog.data.db.AppDatabase
import com.southsouthwest.framelog.data.db.entity.Roll
import com.southsouthwest.framelog.data.db.entity.RollStatus
import com.southsouthwest.framelog.data.db.relation.RollListRow
import com.southsouthwest.framelog.data.repository.RollRepository
import kotlinx.coroutines.ExperimentalCoroutinesApi
import kotlinx.coroutines.FlowPreview
import kotlinx.coroutines.channels.Channel
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.debounce
import kotlinx.coroutines.flow.flatMapLatest
import kotlinx.coroutines.flow.receiveAsFlow
import kotlinx.coroutines.flow.update
import kotlinx.coroutines.launch

// ---------------------------------------------------------------------------
// Tab enum
// ---------------------------------------------------------------------------

enum class RollListTab { ACTIVE, FINISHED, ARCHIVED }

// ---------------------------------------------------------------------------
// UiState
// ---------------------------------------------------------------------------

data class RollListUiState(
    val selectedTab: RollListTab = RollListTab.ACTIVE,
    val searchQuery: String = "",
    val activeRolls: List<RollListRow> = emptyList(),
    val finishedRolls: List<RollListRow> = emptyList(),
    val archivedRolls: List<RollListRow> = emptyList(),
    val isLoading: Boolean = true,
)

// ---------------------------------------------------------------------------
// Events
// ---------------------------------------------------------------------------

sealed class RollListEvent {
    data object NavigateToRollSetup : RollListEvent()
    data class NavigateToRollJournal(val rollId: Int) : RollListEvent()
    /** Emit to show the Load Roll confirmation sheet for [roll]. */
    data class ShowLoadConfirmation(val roll: Roll) : RollListEvent()
    /** Emit to show the delete danger confirmation for [roll]. */
    data class ShowDeleteConfirmation(val roll: Roll) : RollListEvent()
    data class ShowErrorMessage(val message: String) : RollListEvent()
}

// ---------------------------------------------------------------------------
// ViewModel
// ---------------------------------------------------------------------------

@OptIn(ExperimentalCoroutinesApi::class, FlowPreview::class)
class RollListViewModel(application: Application) : AndroidViewModel(application) {

    private val db = AppDatabase.getInstance(application)
    private val rollRepository = RollRepository(db)
    private val appPreferences = AppPreferences(application)

    private val _state = MutableStateFlow(RollListUiState())
    val state: StateFlow<RollListUiState> = _state.asStateFlow()

    private val _events = Channel<RollListEvent>(Channel.BUFFERED)
    val events: Flow<RollListEvent> = _events.receiveAsFlow()

    private val searchQuery = MutableStateFlow("")

    init {
        collectActiveRolls()
        collectFinishedRolls()
        collectArchivedRolls()
    }

    private fun collectActiveRolls() = viewModelScope.launch {
        searchQuery.debounce(300).flatMapLatest { query ->
            rollRepository.searchRollListRowsByStatus(query, RollStatus.ACTIVE.value)
        }.collect { rows ->
            _state.update { it.copy(activeRolls = rows, isLoading = false) }
        }
    }

    private fun collectFinishedRolls() = viewModelScope.launch {
        searchQuery.debounce(300).flatMapLatest { query ->
            rollRepository.searchRollListRowsByStatus(query, RollStatus.FINISHED.value)
        }.collect { rows ->
            _state.update { it.copy(finishedRolls = rows) }
        }
    }

    private fun collectArchivedRolls() = viewModelScope.launch {
        searchQuery.debounce(300).flatMapLatest { query ->
            rollRepository.searchRollListRowsByStatus(query, RollStatus.ARCHIVED.value)
        }.collect { rows ->
            _state.update { it.copy(archivedRolls = rows) }
        }
    }

    // ---------------------------------------------------------------------------
    // User actions
    // ---------------------------------------------------------------------------

    fun onTabSelected(tab: RollListTab) {
        _state.update { it.copy(selectedTab = tab) }
    }

    fun onSearchQueryChanged(query: String) {
        searchQuery.value = query
        _state.update { it.copy(searchQuery = query) }
    }

    fun onAddRollTapped() = viewModelScope.launch {
        _events.send(RollListEvent.NavigateToRollSetup)
    }

    fun onRollCardTapped(rollId: Int) = viewModelScope.launch {
        _events.send(RollListEvent.NavigateToRollJournal(rollId))
    }

    fun onLoadRollRequested(roll: Roll) = viewModelScope.launch {
        // Show confirmation sheet — actual load happens in onLoadRollConfirmed
        _events.send(RollListEvent.ShowLoadConfirmation(roll))
    }

    fun onLoadRollConfirmed(roll: Roll) = viewModelScope.launch {
        rollRepository.updateIsLoaded(roll.id, true)
        // If no active roll is currently set, make this the active roll for the Quick Screen
        if (appPreferences.activeRollId == -1) {
            appPreferences.activeRollId = roll.id
        }
    }

    fun onDeleteTapped(roll: Roll) = viewModelScope.launch {
        _events.send(RollListEvent.ShowDeleteConfirmation(roll))
    }

    fun onDeleteConfirmed(roll: Roll) = viewModelScope.launch {
        // Clear SharedPreferences for this roll
        appPreferences.clearRollPreferences(roll.id)
        // If this was the active roll, clear the active roll selection
        if (appPreferences.activeRollId == roll.id) {
            appPreferences.activeRollId = -1
        }
        rollRepository.deleteRoll(roll)
    }

    /**
     * Archives a finished roll. The UI must show a confirmation dialog before calling this —
     * archiving is a one-step state transition (archive/unarchive) not a destructive action,
     * but we still confirm per spec.
     */
    fun onArchiveConfirmed(roll: Roll) = viewModelScope.launch {
        rollRepository.archiveRoll(roll.id)
    }

    /**
     * Unarchives a roll back to finished status. The UI must confirm before calling this.
     */
    fun onUnarchiveConfirmed(roll: Roll) = viewModelScope.launch {
        rollRepository.unarchiveRoll(roll.id)
    }
}

package com.southsouthwest.framelog.ui.rolls

import android.app.Application
import androidx.lifecycle.AndroidViewModel
import androidx.lifecycle.SavedStateHandle
import androidx.lifecycle.viewModelScope
import com.southsouthwest.framelog.data.AppPreferences
import com.southsouthwest.framelog.data.ExportFormat
import com.southsouthwest.framelog.data.db.AppDatabase
import com.southsouthwest.framelog.data.db.relation.RollWithDetails
import com.southsouthwest.framelog.data.repository.RollRepository
import com.southsouthwest.framelog.ui.util.ExportFormatter
import kotlinx.coroutines.channels.Channel
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.receiveAsFlow
import kotlinx.coroutines.flow.update
import kotlinx.coroutines.launch

// ---------------------------------------------------------------------------
// UiState
// ---------------------------------------------------------------------------

data class RollJournalUiState(
    val roll: RollWithDetails? = null,
    /** The "current" frame number — the frame the Quick Screen is pointing at. */
    val currentFrameNumber: Int = 1,
    val showExportSheet: Boolean = false,
    val selectedExportFormat: ExportFormat = ExportFormat.CSV,
    val isLoading: Boolean = true,
    val isActionInProgress: Boolean = false,
)

// ---------------------------------------------------------------------------
// Events
// ---------------------------------------------------------------------------

sealed class RollJournalEvent {
    data class NavigateToFrameDetail(val frameId: Int, val rollId: Int) : RollJournalEvent()
    /** Emit to show the Finish Roll confirmation sheet. */
    data object ShowFinishRollConfirmation : RollJournalEvent()
    /** Emit to show the Load Roll confirmation sheet. */
    data object ShowLoadRollConfirmation : RollJournalEvent()
    /** Emit to show the Archive confirmation sheet. */
    data object ShowArchiveConfirmation : RollJournalEvent()
    /** Emit to show the Unarchive confirmation sheet. */
    data object ShowUnarchiveConfirmation : RollJournalEvent()
    /** Emit to show the delete danger confirmation. */
    data object ShowDeleteConfirmation : RollJournalEvent()
    /**
     * Emit to hand the formatted export content to the Android share sheet.
     * The UI creates the Intent; ViewModel provides the content and MIME type.
     */
    data class ShareExportContent(
        val content: String,
        val mimeType: String,
        val suggestedFilename: String,
    ) : RollJournalEvent()
    data object NavigateBack : RollJournalEvent()
    data class ShowErrorMessage(val message: String) : RollJournalEvent()
}

// ---------------------------------------------------------------------------
// ViewModel
// ---------------------------------------------------------------------------

class RollJournalViewModel(
    application: Application,
    savedState: SavedStateHandle,
) : AndroidViewModel(application) {

    private val rollId: Int = checkNotNull(savedState["rollId"]) {
        "RollJournalViewModel requires a 'rollId' nav argument"
    }

    private val db = AppDatabase.getInstance(application)
    private val rollRepository = RollRepository(db)
    private val appPreferences = AppPreferences(application)

    private val _state = MutableStateFlow(RollJournalUiState())
    val state: StateFlow<RollJournalUiState> = _state.asStateFlow()

    private val _events = Channel<RollJournalEvent>(Channel.BUFFERED)
    val events: Flow<RollJournalEvent> = _events.receiveAsFlow()

    init {
        viewModelScope.launch {
            rollRepository.getRollById(rollId).collect { rollWithDetails ->
                if (rollWithDetails == null) {
                    // Roll was deleted from outside this screen (e.g. from Roll List while
                    // the Journal was open in the back stack). Navigate back immediately.
                    _events.send(RollJournalEvent.NavigateBack)
                    return@collect
                }
                val currentFrame = appPreferences.getCurrentFrameNumber(rollId)
                _state.update {
                    it.copy(
                        roll = rollWithDetails,
                        currentFrameNumber = currentFrame,
                        isLoading = false,
                    )
                }
            }
        }
    }

    // ---------------------------------------------------------------------------
    // User actions
    // ---------------------------------------------------------------------------

    fun onFrameCardTapped(frameId: Int) = viewModelScope.launch {
        _events.send(RollJournalEvent.NavigateToFrameDetail(frameId, rollId))
    }

    fun onExportTapped() {
        _state.update {
            it.copy(
                showExportSheet = true,
                selectedExportFormat = appPreferences.defaultExportFormat,
            )
        }
    }

    fun onExportFormatSelected(format: ExportFormat) {
        _state.update { it.copy(selectedExportFormat = format) }
    }

    fun onExportDismissed() {
        _state.update { it.copy(showExportSheet = false) }
    }

    fun onExportConfirmed() = viewModelScope.launch {
        _state.update { it.copy(isActionInProgress = true, showExportSheet = false) }
        try {
            val export = rollRepository.getRollForExport(rollId)
            val rollName = _state.value.roll?.roll?.name ?: "roll_$rollId"
            val format = _state.value.selectedExportFormat

            val (content, mimeType, extension) = when (format) {
                ExportFormat.CSV -> Triple(
                    ExportFormatter.toCsv(export),
                    "text/csv",
                    "csv",
                )
                ExportFormat.JSON -> Triple(
                    ExportFormatter.toJson(export),
                    "application/json",
                    "json",
                )
                ExportFormat.PLAIN_TEXT -> Triple(
                    ExportFormatter.toPlainText(export),
                    "text/plain",
                    "txt",
                )
            }

            val filename = sanitizeFilename(rollName) + ".$extension"
            rollRepository.updateLastExported(rollId, System.currentTimeMillis())

            _events.send(
                RollJournalEvent.ShareExportContent(
                    content = content,
                    mimeType = mimeType,
                    suggestedFilename = filename,
                )
            )
        } catch (e: Exception) {
            _events.send(RollJournalEvent.ShowErrorMessage("Export failed: ${e.message}"))
        } finally {
            _state.update { it.copy(isActionInProgress = false) }
        }
    }

    // ---------------------------------------------------------------------------
    // Roll state transitions (confirmation is handled by the UI before calling these)
    // ---------------------------------------------------------------------------

    fun onLoadRollTapped() = viewModelScope.launch {
        _events.send(RollJournalEvent.ShowLoadRollConfirmation)
    }

    fun onLoadRollConfirmed() = viewModelScope.launch {
        _state.update { it.copy(isActionInProgress = true) }
        rollRepository.updateIsLoaded(rollId, true)
        if (appPreferences.activeRollId == -1) {
            appPreferences.activeRollId = rollId
        }
        _state.update { it.copy(isActionInProgress = false) }
    }

    fun onFinishRollTapped() = viewModelScope.launch {
        _events.send(RollJournalEvent.ShowFinishRollConfirmation)
    }

    fun onFinishRollConfirmed() = viewModelScope.launch {
        _state.update { it.copy(isActionInProgress = true) }
        rollRepository.finishRoll(rollId, System.currentTimeMillis())
        // Unload the roll — a finished roll is no longer in a camera
        rollRepository.updateIsLoaded(rollId, false)
        // If this was the active roll, clear the selection
        if (appPreferences.activeRollId == rollId) {
            appPreferences.activeRollId = -1
        }
        _state.update { it.copy(isActionInProgress = false) }
    }

    fun onArchiveTapped() = viewModelScope.launch {
        _events.send(RollJournalEvent.ShowArchiveConfirmation)
    }

    fun onArchiveConfirmed() = viewModelScope.launch {
        _state.update { it.copy(isActionInProgress = true) }
        rollRepository.archiveRoll(rollId)
        _state.update { it.copy(isActionInProgress = false) }
    }

    fun onUnarchiveTapped() = viewModelScope.launch {
        _events.send(RollJournalEvent.ShowUnarchiveConfirmation)
    }

    fun onUnarchiveConfirmed() = viewModelScope.launch {
        _state.update { it.copy(isActionInProgress = true) }
        rollRepository.unarchiveRoll(rollId)
        _state.update { it.copy(isActionInProgress = false) }
    }

    fun onDeleteTapped() = viewModelScope.launch {
        _events.send(RollJournalEvent.ShowDeleteConfirmation)
    }

    fun onDeleteConfirmed() = viewModelScope.launch {
        val roll = _state.value.roll?.roll ?: return@launch
        appPreferences.clearRollPreferences(rollId)
        if (appPreferences.activeRollId == rollId) {
            appPreferences.activeRollId = -1
        }
        rollRepository.deleteRoll(roll)
        _events.send(RollJournalEvent.NavigateBack)
    }

    // ---------------------------------------------------------------------------
    // Helpers
    // ---------------------------------------------------------------------------

    private fun sanitizeFilename(name: String): String =
        name.replace(Regex("[^a-zA-Z0-9._-]"), "_")
}

package com.southsouthwest.framelog.ui.rolls

import android.app.Application
import androidx.lifecycle.AndroidViewModel
import androidx.lifecycle.viewModelScope
import com.southsouthwest.framelog.data.AppPreferences
import com.southsouthwest.framelog.data.db.AppDatabase
