            .width(48.dp)
            .height(28.dp)
            .background(GlanceTheme.colors.surface),
        contentAlignment = Alignment.Center,
    ) {
        Text(
            text = text,
            style = TextStyle(
                fontSize = 15.sp,
                fontWeight = FontWeight.Medium,
                color = color,
                textAlign = TextAlign.Center,
            ),
        )
    }
}

/** Full-width tap target that logs the current frame. */
@Composable
private fun LogFrameBox() {
    Box(
        modifier = GlanceModifier
            .fillMaxWidth()
            .defaultWeight()
            .clickable(actionRunCallback<LogFrameAction>()),
        contentAlignment = Alignment.Center,
    ) {
        Text(
            text = "log frame",
            style = TextStyle(
                fontSize = 15.sp,
                fontWeight = FontWeight.Medium,
                color = GlanceTheme.colors.onSurface,
                textAlign = TextAlign.Center,
            ),
        )
    }
}

/**
 * Full-width tap target shown when all frames after the highest logged frame are exhausted.
 * Tapping opens the app directly to the Roll Journal so the user can finish the roll.
 */
@Composable
private fun RollCompleteBox(rollId: Int) {
    val intent = Intent(Intent.ACTION_VIEW, Uri.parse("framelog://journal/$rollId"))
    Box(
        modifier = GlanceModifier
            .fillMaxWidth()
            .defaultWeight()
            .clickable(actionStartActivity(intent)),
        contentAlignment = Alignment.Center,
    ) {
        Text(
            text = "roll complete →",
            style = TextStyle(
                fontSize = 15.sp,
                fontWeight = FontWeight.Medium,
                color = GlanceTheme.colors.primary,
                textAlign = TextAlign.Center,
            ),
        )
    }
}

/** Thin horizontal rule between widget layout sections. */
@Composable
private fun HorizontalDivider() {
    Box(
        modifier = GlanceModifier
            .fillMaxWidth()
            .height(1.dp)
            .background(GlanceTheme.colors.surfaceVariant),
    ) {}
}
